#include <iostream>
#include <cstdint>

int main() {
    // Test case: x and y are both negative
    int32_t x = -10;  // 0xFFFFFFF6 in two's complement
    int32_t y = -20;  // 0xFFFFFFEC in two's complement

    // As signed: -10 > -20 (true)
    bool sgt = x > y;

    // As unsigned: 0xFFFFFFF6 > 0xFFFFFFEC (true)
    // But note: -10 as unsigned is large positive number
    bool ugt = (uint32_t)x > (uint32_t)y;

    // x - y = -10 - (-20) = 10
    int32_t sub = x - y;  // 10

    // If C >= 0, say C = 5
    int32_t C = 5;

    // (x - y) < C? 10 < 5 is false
    bool cmp = sub < C;

    std::cout << "x = " << x << " (0x" << std::hex << (uint32_t)x << std::dec << ")" << std::endl;
    std::cout << "y = " << y << " (0x" << std::hex << (uint32_t)y << std::dec << ")" << std::endl;
    std::cout << "x s> y: " << sgt << std::endl;
    std::cout << "x u> y: " << ugt << std::endl;
    std::cout << "x - y = " << sub << std::endl;
    std::cout << "(x - y) < " << C << ": " << cmp << std::endl;

    // The optimization says: if x s> y and C >= 0, then (x - y) < C is false
    // Here x s> y is true, C >= 0 is true, and (x - y) < C is false ✓

    // But with the patch: if x u> y (with samesign) and C >= 0, then (x - y) < C is false
    // Here x u> y is true (both negative, same sign), C >= 0 is true
    // and (x - y) < C is false ✓ (still works in this case)

    // Let's test another case
    int32_t x2 = -20;  // 0xFFFFFFEC
    int32_t y2 = -10;  // 0xFFFFFFF6

    bool sgt2 = x2 > y2;  // -20 > -10 is false
    bool ugt2 = (uint32_t)x2 > (uint32_t)y2;  // 0xFFFFFFEC > 0xFFFFFFF6 is false

    int32_t sub2 = x2 - y2;  // -20 - (-10) = -10

    std::cout << "\nSecond test:" << std::endl;
    std::cout << "x2 = " << x2 << ", y2 = " << y2 << std::endl;
    std::cout << "x2 s> y2: " << sgt2 << std::endl;
    std::cout << "x2 u> y2: " << ugt2 << std::endl;
    std::cout << "x2 - y2 = " << sub2 << std::endl;

    return 0;
}
EOF

