    // Test case: x positive, y negative (different signs)
    int32_t x = 10;    // 0x0000000A
    int32_t y = -20;   // 0xFFFFFFEC

    // As signed: 10 > -20 (true)
    bool sgt = x > y;

    // As unsigned: 0x0000000A > 0xFFFFFFEC (false!)
    bool ugt = (uint32_t)x > (uint32_t)y;

