    std::cout << "y = " << y << " (0x" << std::hex << (uint32_t)y << std::dec << ")" << std::endl;
    std::cout << "x s> y: " << sgt << std::endl;
    std::cout << "x u> y: " << ugt << std::endl;
    std::cout << "x - y = " << sub << std::endl;

    // The key insight: if x and y have different signs,
    // then x u> y is NOT equivalent to x s> y!
    // In fact, if x is positive and y is negative,
    // x u> y is false but x s> y is true.

    // So if we have "x u> y" with samesign=false (or unspecified),
    // we can't assume x and y have the same sign.
    // But if we have "x u> y" with samesign=true,
    // then we know x and y have the same sign.

