// Simulate the optimization logic
bool optimization_applies(bool x_sgt_y, bool x_ugt_y_samesign, int32_t C) {
    // Original: only if x s> y
    // Patched: if x s> y OR (x u> y with samesign)

    bool condition_met = x_sgt_y || x_ugt_y_samesign;
    if (!condition_met) return false;

    // Check C >= 0
    if (C < 0) return false;

    // Optimization says: (x - y) < C is false
    return true;
}

int main() {
    // Test various cases

    // Case 1: x s> y, C >= 0
    assert(optimization_applies(true, false, 5) == true);

    // Case 2: x s> y, C < 0
    assert(optimization_applies(true, false, -5) == false);

    // Case 3: x u> y with samesign, C >= 0
    assert(optimization_applies(false, true, 5) == true);

    // Case 4: x u> y with samesign, C < 0
    assert(optimization_applies(false, true, -5) == false);

    // Case 5: neither condition
    assert(optimization_applies(false, false, 5) == false);

    std::cout << "All tests passed!" << std::endl;

    // Now test with actual values
    // x = -10, y = -20, C = 5
    // x s> y: true, x u> y with samesign: true
    // C >= 0: true
    // Optimization applies: true
    assert(optimization_applies(true, true, 5) == true);

    // x = -20, y = -10, C = 5
    // x s> y: false, x u> y with samesign: false
    // Optimization applies: false
    assert(optimization_applies(false, false, 5) == false);

    std::cout << "All value tests passed!" << std::endl;

    return 0;
}
